void MRFTWIMark::UpdateFeature()
{
	CATFmFeatureFacade FeatFacadeOnTWIMark(_CredentialForTWI, this);
	HRESULT rc = FeatFacadeOnTWIMark.IsUpToDate();
	if (S_FALSE == rc)
	{
		rc = FeatFacadeOnTWIMark.Update();
		if (SUCCEEDED(rc))
		{
			CATBaseUnknown *pTWIObject = NULL;
			rc = FeatFacadeOnTWIMark.QueryInterfaceOnFeature(IID_CATBaseUnknown, (void**)&pTWIObject);
			if (SUCCEEDED(rc) && NULL != pTWIObject)
			{
				CATPrtUpdateCom *pUpdateCommand = new CATPrtUpdateCom(pTWIObject, 0, 0);

				pTWIObject->Release();
				pTWIObject = NULL;
			}
		}
	}
}

